interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
}

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Waiter[];
  private scheduledWakeup: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a finite positive number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate < 0) {
      throw new RangeError("refillRate must be a finite non-negative number");
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a finite positive number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.scheduledWakeup = null;
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed > 0 && this.refillRate > 0) {
      const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    }

    this.lastRefillTime = now;
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      throw new RangeError("tokens must be a finite positive number");
    }

    if (tokens > this.maxTokens) {
      return false;
    }

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();

    if (this.scheduledWakeup !== null) {
      clearTimeout(this.scheduledWakeup);
      this.scheduledWakeup = null;
    }

    this.drainQueue();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      return Promise.reject(new RangeError("tokens must be a finite positive number"));
    }

    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds maxTokens (${this.maxTokens}); ` +
          `the bucket can never satisfy this request`
        )
      );
    }

    this.applyRefill();

    if (this.waitQueue.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    return new Promise<void>((resolve) => {
      this.waitQueue.push({ tokens, resolve });
      this.scheduleNextWakeup();
    });
  }

  private drainQueue(): void {
    this.applyRefill();

    while (this.waitQueue.length > 0) {
      const waiter = this.waitQueue[0];

      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.waitQueue.shift();
        waiter.resolve();
      } else {
        break;
      }
    }

    if (this.waitQueue.length > 0) {
      this.scheduleNextWakeup();
    }
  }

  private scheduleNextWakeup(): void {
    if (this.scheduledWakeup !== null) {
      return;
    }

    if (this.waitQueue.length === 0) {
      return;
    }

    if (this.refillRate <= 0) {
      // No refill will ever occur; waiters are stuck until reset() is called.
      return;
    }

    const waiter = this.waitQueue[0];
    const deficit = waiter.tokens - this.currentTokens;
    const msNeeded = (deficit / this.refillRate) * this.refillIntervalMs;
    const delay = Math.max(0, msNeeded);

    this.scheduledWakeup = setTimeout(() => {
      this.scheduledWakeup = null;
      this.drainQueue();
    }, delay);
  }
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldBounds {
  min: number;
  max: number;
}

const FIELD_BOUNDS: Record<keyof CronExpression, FieldBounds> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function strictInt(s: string, context: string): number {
  const n = Number(s);
  if (!Number.isInteger(n)) {
    throw new RangeError(`Invalid integer "${s}" in field: ${context}`);
  }
  return n;
}

function assertInBounds(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of range [${min}, ${max}] in field: ${context}`
    );
  }
}

function expandRange(lo: number, hi: number, step: number, min: number, max: number, raw: string): number[] {
  if (lo > hi) throw new RangeError(`Range start exceeds end in field: ${raw}`);
  assertInBounds(lo, min, max, raw);
  assertInBounds(hi, min, max, raw);
  if (step < 1) throw new RangeError(`Step must be >= 1 in field: ${raw}`);

  const values: number[] = [];
  for (let i = lo; i <= hi; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  const raw = segment;

  // Step value: */n  or  lo-hi/n  or  start/n
  if (segment.includes('/')) {
    const slashAt = segment.indexOf('/');
    const baseStr = segment.slice(0, slashAt);
    const stepStr = segment.slice(slashAt + 1);

    if (stepStr.includes('/')) {
      throw new SyntaxError(`Unexpected extra "/" in field: ${raw}`);
    }

    const step = strictInt(stepStr, raw);
    if (step < 1) throw new RangeError(`Step must be >= 1 in field: ${raw}`);

    if (baseStr === '*') {
      return expandRange(min, max, step, min, max, raw);
    }

    if (baseStr.includes('-')) {
      const [loStr, hiStr] = baseStr.split('-');
      if (!loStr || !hiStr) throw new SyntaxError(`Malformed range in field: ${raw}`);
      return expandRange(strictInt(loStr, raw), strictInt(hiStr, raw), step, min, max, raw);
    }

    // start/n — treat start as lo, max as hi
    const lo = strictInt(baseStr, raw);
    return expandRange(lo, max, step, min, max, raw);
  }

  // Wildcard
  if (segment === '*') {
    return expandRange(min, max, 1, min, max, raw);
  }

  // Range: lo-hi
  if (segment.includes('-')) {
    const dashAt = segment.indexOf('-');
    const loStr = segment.slice(0, dashAt);
    const hiStr = segment.slice(dashAt + 1);
    if (!loStr || !hiStr || hiStr.includes('-')) {
      throw new SyntaxError(`Malformed range in field: ${raw}`);
    }
    return expandRange(strictInt(loStr, raw), strictInt(hiStr, raw), 1, min, max, raw);
  }

  // Single value
  const n = strictInt(segment, raw);
  assertInBounds(n, min, max, raw);
  return [n];
}

function parseField(field: string, bounds: FieldBounds): number[] {
  if (!field || field.trim() === '') {
    throw new SyntaxError(`Empty cron field`);
  }

  const { min, max } = bounds;
  const segments = field.split(',');
  const seen = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (!trimmed) throw new SyntaxError(`Empty segment in field: "${field}"`);
    for (const v of parseSegment(trimmed, min, max)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== 'string') {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;

  return {
    minute:     parseField(minuteRaw, FIELD_BOUNDS.minute),
    hour:       parseField(hourRaw,   FIELD_BOUNDS.hour),
    dayOfMonth: parseField(domRaw,    FIELD_BOUNDS.dayOfMonth),
    month:      parseField(monthRaw,  FIELD_BOUNDS.month),
    dayOfWeek:  parseField(dowRaw,    FIELD_BOUNDS.dayOfWeek),
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | bigint | symbol | null | undefined;
type NestedValue = Primitive | NestedObject | NestedArray;
interface NestedObject extends Record<string, NestedValue> {}
interface NestedArray extends Array<NestedValue> {}

function isExpandable(value: unknown): value is NestedObject | NestedArray {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return true;
  const proto = Object.getPrototypeOf(value);
  // Only expand plain objects — treat Date, Map, Set, RegExp, etc. as leaves
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  seen = new WeakSet<object>()
): Record<string, Primitive> {
  if (typeof obj !== "object" || obj === null) {
    throw new TypeError(`Expected a plain object, received: ${obj === null ? "null" : typeof obj}`);
  }

  if (seen.has(obj)) {
    throw new Error(
      `Circular reference detected${prefix ? ` at key "${prefix}"` : ""}`
    );
  }
  seen.add(obj);

  const result: Record<string, Primitive> = {};

  for (const key of Object.keys(obj)) {
    const value = obj[key];
    const flatKey = prefix ? `${prefix}.${key}` : key;

    if (isExpandable(value)) {
      const children = Object.keys(value as object);
      if (children.length === 0) {
        // Empty object or array — emit nothing; no meaningful leaf to represent
        continue;
      }
      Object.assign(
        result,
        flattenObject(value as Record<string, unknown>, flatKey, seen)
      );
    } else {
      result[flatKey] = value as Primitive;
    }
  }

  // Remove from seen so the same object reference is safe across sibling branches
  seen.delete(obj);

  return result;
}

export default flattenObject;

const FIELD_RANGES: Record<string, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

const FIELD_NAMES = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;
type FieldName = typeof FIELD_NAMES[number];

export interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

function clamp(val: number, min: number, max: number): number {
  if (val < min || val > max) {
    throw new RangeError(`Value ${val} out of range [${min}, ${max}]`);
  }
  return val;
}

function parseField(token: string, field: FieldName): number[] {
  const [min, max] = FIELD_RANGES[field];

  // Comma-separated list — recurse on each segment
  if (token.includes(",")) {
    const parts = token.split(",");
    if (parts.some((p) => p.trim() === ""))
      throw new SyntaxError(`Empty segment in list: "${token}"`);
    const merged = parts.flatMap((p) => parseField(p.trim(), field));
    return [...new Set(merged)].sort((a, b) => a - b);
  }

  // Step: */N or start-end/N
  if (token.includes("/")) {
    const [rangePart, stepPart] = token.split("/");
    if (!stepPart || stepPart === "")
      throw new SyntaxError(`Missing step in: "${token}"`);
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step < 1)
      throw new RangeError(`Step must be integer ≥ 1, got: "${stepPart}"`);

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map((x) => parseInt(x, 10));
      if (isNaN(s) || isNaN(e))
        throw new SyntaxError(`Bad range in step: "${token}"`);
      start = clamp(s, min, max);
      end = clamp(e, min, max);
      if (start > end)
        throw new RangeError(`Range start > end in: "${token}"`);
    } else {
      start = clamp(parseInt(rangePart, 10), min, max);
      if (isNaN(start))
        throw new SyntaxError(`Bad start in step: "${token}"`);
      end = max;
    }

    const values: number[] = [];
    for (let v = start; v <= end; v += step) values.push(v);
    return values;
  }

  // Range: N-M
  if (token.includes("-")) {
    const [s, e] = token.split("-");
    const start = parseInt(s, 10);
    const end = parseInt(e, 10);
    if (isNaN(start) || isNaN(end))
      throw new SyntaxError(`Bad range: "${token}"`);
    clamp(start, min, max);
    clamp(end, min, max);
    if (start > end)
      throw new RangeError(`Range start > end: "${token}"`);
    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  // Wildcard
  if (token === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // Literal number
  const num = parseInt(token, 10);
  if (isNaN(num) || token.trim() !== String(num))
    throw new SyntaxError(`Invalid token "${token}" for field "${field}"`);
  return [clamp(num, min, max)];
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string")
    throw new TypeError("Expression must be a string");

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5)
    throw new SyntaxError(
      `Expected 5 fields, got ${fields.length}: "${expression}"`
    );

  const result = {} as CronResult;
  for (let i = 0; i < FIELD_NAMES.length; i++) {
    const name = FIELD_NAMES[i];
    result[name] = parseField(fields[i], name);
  }
  return result;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(from: number, to: number): number[] {
  return Array.from({ length: to - from + 1 }, (_, i) => i + from);
}

function clamp(values: number[], min: number, max: number): number[] {
  return values.filter((v) => v >= min && v <= max);
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step: */n or x-y/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step: ${stepStr}`);
    const base =
      rangePart === "*" ? range(min, max) : parseSegment(rangePart, min, max);
    return base.filter((v) => (v - base[0]) % step === 0);
  }

  // Range: x-y
  if (segment.includes("-")) {
    const [fromStr, toStr] = segment.split("-");
    const from = parseInt(fromStr, 10);
    const to = parseInt(toStr, 10);
    if (isNaN(from) || isNaN(to)) throw new Error(`Invalid range: ${segment}`);
    return clamp(range(from, to), min, max);
  }

  // Wildcard
  if (segment === "*") return range(min, max);

  // Number
  const n = parseInt(segment, 10);
  if (isNaN(n)) throw new Error(`Invalid value: ${segment}`);
  if (n < min || n > max) throw new Error(`Value ${n} out of range [${min},${max}]`);
  return [n];
}

function parseField(field: string, min: number, max: number): number[] {
  const parts = field.split(",");
  const values = new Set<number>();
  for (const part of parts) {
    for (const v of parseSegment(part.trim(), min, max)) {
      values.add(v);
    }
  }
  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) throw new Error(`Expected 5 fields, got ${fields.length}`);

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = fields;
  const order: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];
  const inputs = [minuteStr, hourStr, domStr, monthStr, dowStr];

  const result = {} as CronResult;
  for (let i = 0; i < 5; i++) {
    const field = order[i];
    const [min, max] = FIELD_RANGES[field];
    result[field] = parseField(inputs[i], min, max);
  }

  return result;
}

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: Record<keyof CronResult, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

/** Parse only bare non-negative integers. Rejects floats, "3e5", "", leading signs. */
function parseStrictInt(s: string, context: string): number {
  if (!/^\d+$/.test(s)) {
    throw new TypeError(`Expected an integer, got "${s}" in "${context}"`);
  }
  return parseInt(s, 10);
}

function assertInBounds(value: number, config: FieldConfig, context: string): void {
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} out of bounds [${config.min}–${config.max}] in "${context}"`,
    );
  }
}

function expandRange(start: number, end: number): number[] {
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function parseSegment(raw: string, config: FieldConfig): number[] {
  const segment = raw.trim();
  if (segment === "") throw new TypeError(`Empty cron segment`);

  const { min, max } = config;

  // ── Step expressions ──────────────────────────────────────────────────────
  const slashCount = (segment.match(/\//g) ?? []).length;
  if (slashCount > 1) {
    throw new TypeError(`Too many "/" characters in segment "${segment}"`);
  }

  if (slashCount === 1) {
    const slashIdx = segment.indexOf("/");
    const baseStr  = segment.slice(0, slashIdx);
    const stepStr  = segment.slice(slashIdx + 1);

    const step = parseStrictInt(stepStr, segment);
    if (step === 0) throw new RangeError(`Step value cannot be zero in "${segment}"`);

    let start: number;
    let end: number;

    if (baseStr === "*") {
      start = min;
      end   = max;
    } else if (baseStr.includes("-")) {
      const dashCount = (baseStr.match(/-/g) ?? []).length;
      if (dashCount !== 1) throw new TypeError(`Invalid range "${baseStr}" in "${segment}"`);
      const dashIdx = baseStr.indexOf("-");
      const lo = parseStrictInt(baseStr.slice(0, dashIdx), segment);
      const hi = parseStrictInt(baseStr.slice(dashIdx + 1), segment);
      assertInBounds(lo, config, segment);
      assertInBounds(hi, config, segment);
      if (lo > hi) throw new RangeError(`Start ${lo} > end ${hi} in "${segment}"`);
      start = lo;
      end   = hi;
    } else {
      const lo = parseStrictInt(baseStr, segment);
      assertInBounds(lo, config, segment);
      start = lo;
      end   = max;
    }

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // ── Wildcard ──────────────────────────────────────────────────────────────
  if (segment === "*") return expandRange(min, max);

  // ── Range ─────────────────────────────────────────────────────────────────
  if (segment.includes("-")) {
    const dashCount = (segment.match(/-/g) ?? []).length;
    if (dashCount !== 1) throw new TypeError(`Invalid range "${segment}"`);
    const dashIdx = segment.indexOf("-");
    const start = parseStrictInt(segment.slice(0, dashIdx), segment);
    const end   = parseStrictInt(segment.slice(dashIdx + 1), segment);
    assertInBounds(start, config, segment);
    assertInBounds(end,   config, segment);
    if (start > end) throw new RangeError(`Start ${start} > end ${end} in "${segment}"`);
    return expandRange(start, end);
  }

  // ── Single value ──────────────────────────────────────────────────────────
  const num = parseStrictInt(segment, segment);
  assertInBounds(num, config, segment);
  return [num];
}

function parseField(field: string, config: FieldConfig): number[] {
  const parts = field.split(",");
  const values = parts.flatMap(part => parseSegment(part, config));
  return [...new Set(values)].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new TypeError(`Cron expression must be a non-empty string`);
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new TypeError(
      `Cron expression must have exactly 5 fields (got ${fields.length}): "${expression}"`,
    );
  }

  const [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr] = fields;

  return {
    minute:     parseField(minuteStr,     FIELD_CONFIGS.minute),
    hour:       parseField(hourStr,       FIELD_CONFIGS.hour),
    dayOfMonth: parseField(dayOfMonthStr, FIELD_CONFIGS.dayOfMonth),
    month:      parseField(monthStr,      FIELD_CONFIGS.month),
    dayOfWeek:  parseField(dayOfWeekStr,  FIELD_CONFIGS.dayOfWeek),
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const val = obj[key];

    if (
      val !== null &&
      typeof val === "object" &&
      !Array.isArray(val) &&
      Object.keys(val).length > 0
    ) {
      flattenObject(val as NestedObject, newKey, result);
    } else {
      result[newKey] = Array.isArray(val) ? (JSON.stringify(val) as Primitive) : (val as Primitive);
    }
  }

  return result;
}

export default flattenObject;

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private maxTokens: number;
  private refillRate: number;
  private refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + intervals * this.refillRate
      );
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) throw new RangeError("tokens exceeds maxTokens");

    while (!this.tryConsume(tokens)) {
      this.refill();
      const deficit = tokens - this.currentTokens;
      const intervalsNeeded = Math.ceil(deficit / this.refillRate);
      const elapsed = Date.now() - this.lastRefillTime;
      const waitMs = Math.max(1, intervalsNeeded * this.refillIntervalMs - elapsed);
      await new Promise<void>((resolve) => setTimeout(resolve, waitMs));
    }
  }
}

export default RateLimiter;

const FIELD_RANGES: Record<string, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

function clamp(val: number, min: number, max: number): number {
  if (val < min || val > max) {
    throw new RangeError(`Value ${val} out of range [${min}, ${max}]`);
  }
  return val;
}

function parseField(token: string, field: string): number[] {
  const [min, max] = FIELD_RANGES[field];

  // comma list — recurse, flatten, dedupe, sort
  if (token.includes(",")) {
    const values = token
      .split(",")
      .flatMap((t) => parseField(t.trim(), field));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // wildcard
  if (token === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => i + min);
  }

  // step: */n  or  start/n  or  start-end/n
  if (token.includes("/")) {
    const [rangePart, stepPart] = token.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step < 1) throw new RangeError(`Invalid step: ${stepPart}`);

    let start = min;
    let end = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [s, e] = rangePart.split("-").map((v) => parseInt(v, 10));
        start = clamp(s, min, max);
        end = clamp(e, min, max);
        if (start > end) throw new RangeError(`Invalid range ${rangePart}`);
      } else {
        start = clamp(parseInt(rangePart, 10), min, max);
      }
    }

    const result: number[] = [];
    for (let v = start; v <= end; v += step) result.push(v);
    return result;
  }

  // range: a-b
  if (token.includes("-")) {
    const [s, e] = token.split("-").map((v) => parseInt(v, 10));
    const start = clamp(s, min, max);
    const end = clamp(e, min, max);
    if (start > end) throw new RangeError(`Invalid range ${token}`);
    return Array.from({ length: end - start + 1 }, (_, i) => i + start);
  }

  // single number
  const n = parseInt(token, 10);
  if (isNaN(n)) throw new TypeError(`Invalid token: ${token}`);
  return [clamp(n, min, max)];
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") throw new TypeError("Expression must be string");

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) throw new Error(`Expected 5 fields, got ${parts.length}`);

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = parts;
  const fields = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;

  const [minute, hour, dayOfMonth, month, dayOfWeek] = [
    minuteRaw, hourRaw, domRaw, monthRaw, dowRaw,
  ].map((token, i) => parseField(token, fields[i]));

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface QueueEntry {
  tokens: number;
  resolve: () => void;
  reject: (err: Error) => void;
}

// Max safe value for setTimeout (2^31 - 1 ms ≈ 24.8 days)
const MAX_TIMER_DELAY_MS = 2_147_483_647;

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;

  private currentTokens: number;
  private lastRefillTime: number;
  private readonly queue: QueueEntry[];
  private scheduledTimer: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError(`maxTokens must be a finite positive number, got ${maxTokens}`);
    }
    if (!Number.isFinite(refillRate) || refillRate <= 0) {
      throw new RangeError(`refillRate must be a finite positive number, got ${refillRate}`);
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError(`refillIntervalMs must be a finite positive number, got ${refillIntervalMs}`);
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
    this.queue = [];
    this.scheduledTimer = null;
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsedMs = now - this.lastRefillTime;

    if (elapsedMs > 0) {
      const added = (elapsedMs / this.refillIntervalMs) * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + added);
      this.lastRefillTime = now;
    }
  }

  private drainQueue(): void {
    while (this.queue.length > 0) {
      const head = this.queue[0]!;

      if (this.currentTokens >= head.tokens) {
        this.currentTokens -= head.tokens;
        this.queue.shift();
        head.resolve();
      } else {
        break;
      }
    }

    this.scheduleNextWakeup();
  }

  private scheduleNextWakeup(): void {
    if (this.scheduledTimer !== null) {
      clearTimeout(this.scheduledTimer);
      this.scheduledTimer = null;
    }

    if (this.queue.length === 0) return;

    const head = this.queue[0]!;
    const deficit = head.tokens - this.currentTokens;
    const msToWait = Math.ceil((deficit / this.refillRate) * this.refillIntervalMs);

    // Clamp to safe setTimeout range; if clamped, drainQueue will re-schedule on wakeup
    const delay = Math.max(1, Math.min(msToWait, MAX_TIMER_DELAY_MS));

    this.scheduledTimer = setTimeout(() => {
      this.scheduledTimer = null;
      this.applyRefill();
      this.drainQueue();
    }, delay);
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      throw new RangeError(`tokens must be a finite positive number, got ${tokens}`);
    }

    // Silently reject impossible requests rather than throwing — caller can branch on false
    if (tokens > this.maxTokens) return false;

    this.applyRefill();

    // Preserve fairness: don't allow tryConsume to cut ahead of queued waiters
    if (this.queue.length > 0) return false;

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();

    // Drain as many waiters as possible with the freshly-filled bucket
    this.drainQueue();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      return Promise.reject(
        new RangeError(`tokens must be a finite positive number, got ${tokens}`)
      );
    }

    // Permanently unsatisfiable — reject immediately rather than deadlock forever
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds maxTokens ${this.maxTokens}; request can never be satisfied`
        )
      );
    }

    this.applyRefill();

    // Fast path: no queue, enough tokens available right now
    if (this.queue.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    // Slow path: enqueue and wait for scheduled wakeup
    return new Promise<void>((resolve, reject) => {
      this.queue.push({ tokens, resolve, reject });

      // Only schedule a new wakeup if we just added the first entry (existing timer handles the rest)
      if (this.queue.length === 1) {
        this.scheduleNextWakeup();
      }
    });
  }
}

type Scalar = string | number | boolean | null | undefined | bigint | symbol;
type Flattenable = { [key: string]: unknown } | unknown[];
type FlatObject = Record<string, Scalar>;

const isPlainObject = (value: unknown): value is Record<string, unknown> =>
  value !== null &&
  typeof value === "object" &&
  (Object.getPrototypeOf(value) === Object.prototype ||
    Object.getPrototypeOf(value) === null);

const isTraversable = (value: unknown): value is Flattenable =>
  isPlainObject(value) || Array.isArray(value);

function flatten(
  node: Flattenable,
  prefix: string,
  seen: WeakSet<object>,
  result: FlatObject
): void {
  if (seen.has(node)) {
    throw new TypeError(
      `Circular reference detected at key: "${prefix || "(root)"}"`
    );
  }

  seen.add(node);

  const entries = Array.isArray(node)
    ? node.map((v, i) => [String(i), v] as const)
    : Object.entries(node);

  for (const [key, value] of entries) {
    if (key === "__proto__" || key === "constructor" || key === "prototype") {
      continue;
    }

    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;

    if (isTraversable(value)) {
      flatten(value, fullKey, seen, result);
    } else {
      result[fullKey] = value as Scalar;
    }
  }

  seen.delete(node);
}

function flattenObject(input: Record<string, unknown>): FlatObject {
  if (!isPlainObject(input)) {
    throw new TypeError(
      `Expected a plain object, received: ${
        input === null ? "null" : typeof input
      }`
    );
  }

  const result: FlatObject = {};
  flatten(input, "", new WeakSet(), result);
  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = { [key: string]: unknown };
type FlatObject = { [key: string]: Primitive };

function isPlainObject(value: unknown): value is NestedObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    Object.getPrototypeOf(value) === Object.prototype
  );
}

function flattenObject(
  input: unknown,
  prefix: string = "",
  seen: WeakSet<object> = new WeakSet()
): FlatObject {
  if (input === null || input === undefined) {
    return prefix ? { [prefix]: input as Primitive } : {};
  }

  if (!isPlainObject(input)) {
    return prefix ? { [prefix]: input as Primitive } : {};
  }

  if (seen.has(input)) {
    throw new TypeError(
      `Circular reference detected at key: "${prefix || "(root)"}"`
    );
  }

  const keys = Object.keys(input);

  if (keys.length === 0) {
    return prefix ? { [prefix]: {} as unknown as Primitive } : {};
  }

  seen.add(input);

  const result: FlatObject = {};

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(input, key)) continue;

    const value = input[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (isPlainObject(value)) {
      const nested = flattenObject(value, newKey, seen);
      Object.assign(result, nested);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  seen.delete(input);

  return result;
}

export default flattenObject;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (maxTokens <= 0) throw new RangeError("maxTokens must be greater than 0");
    if (refillRate <= 0) throw new RangeError("refillRate must be greater than 0");
    if (refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be greater than 0");

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervalsElapsed = Math.floor(elapsed / this.refillIntervalMs);

    if (intervalsElapsed > 0) {
      const tokensToAdd = intervalsElapsed * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be greater than 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be greater than 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens exceeds maxTokens capacity"));

    return new Promise((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        const now = Date.now();
        const elapsed = now - this.lastRefillTime;
        const tokensNeeded = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(tokensNeeded / this.refillRate);
        const timeUntilNextRefill = this.refillIntervalMs - (elapsed % this.refillIntervalMs);
        const waitMs = timeUntilNextRefill + (intervalsNeeded - 1) * this.refillIntervalMs;

        setTimeout(attempt, Math.max(0, waitMs));
      };

      attempt();
    });
  }
}

export default RateLimiter;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function rangeArray(min: number, max: number, step = 1): number[] {
  if (step < 1) throw new Error(`Step must be >= 1, got ${step}`);
  const result: number[] = [];
  for (let i = min; i <= max; i += step) result.push(i);
  return result;
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}, ${max}] in ${context}`);
  }
}

function parseSegment(segment: string, min: number, max: number, fieldName: string): number[] {
  // Wildcard: *
  if (segment === "*") {
    return rangeArray(min, max);
  }

  // Step on wildcard: */N
  if (segment.startsWith("*/")) {
    const step = parseInt(segment.slice(2), 10);
    if (isNaN(step)) throw new Error(`Invalid step in "${segment}" for field ${fieldName}`);
    if (step < 1) throw new Error(`Step must be >= 1 in "${segment}" for field ${fieldName}`);
    return rangeArray(min, max, step);
  }

  // Range with optional step: N-M or N-M/S
  if (segment.includes("-")) {
    const [rangePart, stepPart] = segment.split("/");
    const [startStr, endStr] = rangePart.split("-");
    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr,   10);
    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range "${segment}" for field ${fieldName}`);
    }
    assertInRange(start, min, max, `${fieldName} range start`);
    assertInRange(end,   min, max, `${fieldName} range end`);
    if (start > end) throw new Error(`Range start > end in "${segment}" for field ${fieldName}`);
    const step = stepPart !== undefined ? parseInt(stepPart, 10) : 1;
    if (isNaN(step) || step < 1) {
      throw new Error(`Invalid step in "${segment}" for field ${fieldName}`);
    }
    return rangeArray(start, end, step);
  }

  // Plain number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid value "${segment}" for field ${fieldName}`);
  assertInRange(value, min, max, fieldName);
  return [value];
}

function parseField(expression: string, fieldName: CronField): number[] {
  const { min, max } = FIELD_RANGES[fieldName];
  const parts = expression.split(",");
  const values = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    if (!trimmed) throw new Error(`Empty segment in "${expression}" for field ${fieldName}`);
    for (const v of parseSegment(trimmed, min, max, fieldName)) {
      values.add(v);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields, got ${fields.length} in expression "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = fields;

  return {
    minute:     parseField(minuteExpr,     "minute"),
    hour:       parseField(hourExpr,       "hour"),
    dayOfMonth: parseField(dayOfMonthExpr, "dayOfMonth"),
    month:      parseField(monthExpr,      "month"),
    dayOfWeek:  parseField(dayOfWeekExpr,  "dayOfWeek"),
  };
}

