const FIELD_RANGES = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const;

type FieldName = keyof typeof FIELD_RANGES;

export interface CronResult {
  minute:     number[];
  hour:       number[];
  dayOfMonth: number[];
  month:      number[];
  dayOfWeek:  number[];
}

function clamp(val: number, min: number, max: number): number {
  if (val < min || val > max) {
    throw new RangeError(`Value ${val} out of range [${min}, ${max}]`);
  }
  return val;
}

function parseField(token: string, field: FieldName): number[] {
  const { min, max } = FIELD_RANGES[field];

  // comma list — recurse
  if (token.includes(",")) {
    const parts = token.split(",");
    if (parts.some(p => p.trim() === "")) throw new SyntaxError(`Empty segment in list: "${token}"`);
    const merged = new Set(parts.flatMap(p => parseField(p.trim(), field)));
    return [...merged].sort((a, b) => a - b);
  }

  // step: */n or a-b/n
  if (token.includes("/")) {
    const [rangePart, stepPart] = token.split("/");
    if (!stepPart || stepPart === "") throw new SyntaxError(`Missing step in: "${token}"`);
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step < 1) throw new RangeError(`Invalid step "${stepPart}" in: "${token}"`);

    let rangeMin = min;
    let rangeMax = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [lo, hi] = rangePart.split("-").map(s => parseInt(s, 10));
        if (isNaN(lo) || isNaN(hi)) throw new SyntaxError(`Bad range in step: "${token}"`);
        rangeMin = clamp(lo, min, max);
        rangeMax = clamp(hi, min, max);
        if (rangeMin > rangeMax) throw new RangeError(`Inverted range in: "${token}"`);
      } else {
        const start = parseInt(rangePart, 10);
        if (isNaN(start)) throw new SyntaxError(`Bad step base: "${token}"`);
        rangeMin = clamp(start, min, max);
      }
    }

    const result: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) result.push(i);
    return result;
  }

  // range: a-b
  if (token.includes("-")) {
    const parts = token.split("-");
    if (parts.length !== 2) throw new SyntaxError(`Bad range: "${token}"`);
    const lo = parseInt(parts[0], 10);
    const hi = parseInt(parts[1], 10);
    if (isNaN(lo) || isNaN(hi)) throw new SyntaxError(`Non-numeric range: "${token}"`);
    const start = clamp(lo, min, max);
    const end   = clamp(hi, min, max);
    if (start > end) throw new RangeError(`Inverted range: "${token}"`);
    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  // wildcard
  if (token === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // single number
  const n = parseInt(token, 10);
  if (isNaN(n)) throw new SyntaxError(`Unrecognized token "${token}" for field "${field}"`);
  return [clamp(n, min, max)];
}

export function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") throw new TypeError("Expression must be string");

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(`Expected 5 fields, got ${fields.length}: "${expression}"`);
  }

  const [minuteToken, hourToken, domToken, monthToken, dowToken] = fields;

  return {
    minute:     parseField(minuteToken, "minute"),
    hour:       parseField(hourToken,   "hour"),
    dayOfMonth: parseField(domToken,    "dayOfMonth"),
    month:      parseField(monthToken,  "month"),
    dayOfWeek:  parseField(dowToken,    "dayOfWeek"),
  };
}

export default parseCron;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

const FIELD_RANGES: Record<FieldName, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${min}, ${max}] in expression segment: "${context}"`
    );
  }
}

function parseSegment(segment: string, min: number, max: number): number[] {
  if (segment.trim() === "") {
    throw new SyntaxError(`Empty segment is not a valid cron field value`);
  }

  // Comma-separated list — recurse on each part, deduplicate, sort
  if (segment.includes(",")) {
    const seen = new Set<number>();
    for (const part of segment.split(",")) {
      const trimmed = part.trim();
      if (trimmed === "") {
        throw new SyntaxError(`Empty item in comma-separated list: "${segment}"`);
      }
      for (const v of parseSegment(trimmed, min, max)) {
        seen.add(v);
      }
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  // Step value: base/step (base is *, a number, or a range)
  if (segment.includes("/")) {
    const slashCount = (segment.match(/\//g) ?? []).length;
    if (slashCount > 1) {
      throw new SyntaxError(`Multiple slashes in step expression: "${segment}"`);
    }
    const [baseExpr, stepStr] = segment.split("/");
    const step = Number(stepStr);
    if (!Number.isInteger(step) || step <= 0) {
      throw new RangeError(
        `Step value must be a positive integer, got "${stepStr}" in: "${segment}"`
      );
    }

    let rangeMin: number;
    let rangeMax: number;

    if (baseExpr === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (baseExpr.includes("-")) {
      [rangeMin, rangeMax] = parseRangeBounds(baseExpr, min, max);
    } else {
      const start = Number(baseExpr);
      if (!Number.isInteger(start) || isNaN(start)) {
        throw new SyntaxError(`Invalid base in step expression: "${segment}"`);
      }
      assertInRange(start, min, max, segment);
      rangeMin = start;
      rangeMax = max;
    }

    const values: number[] = [];
    for (let v = rangeMin; v <= rangeMax; v += step) {
      values.push(v);
    }
    return values;
  }

  // Range: low-high
  if (segment.includes("-")) {
    const [lo, hi] = parseRangeBounds(segment, min, max);
    return Array.from({ length: hi - lo + 1 }, (_, i) => lo + i);
  }

  // Wildcard
  if (segment === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // Single integer
  const value = Number(segment);
  if (!Number.isInteger(value) || isNaN(value)) {
    throw new SyntaxError(`Non-integer value "${segment}" is not valid in a cron field`);
  }
  assertInRange(value, min, max, segment);
  return [value];
}

function parseRangeBounds(
  expr: string,
  min: number,
  max: number
): [number, number] {
  const dashCount = (expr.match(/-/g) ?? []).length;
  if (dashCount !== 1) {
    throw new SyntaxError(`Invalid range expression: "${expr}"`);
  }
  const [loStr, hiStr] = expr.split("-");
  const lo = Number(loStr);
  const hi = Number(hiStr);

  if (!Number.isInteger(lo) || isNaN(lo)) {
    throw new SyntaxError(`Non-integer range start "${loStr}" in: "${expr}"`);
  }
  if (!Number.isInteger(hi) || isNaN(hi)) {
    throw new SyntaxError(`Non-integer range end "${hiStr}" in: "${expr}"`);
  }

  assertInRange(lo, min, max, expr);
  assertInRange(hi, min, max, expr);

  if (lo > hi) {
    throw new RangeError(
      `Range start ${lo} must not exceed range end ${hi} in: "${expr}"`
    );
  }

  return [lo, hi];
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`Cron expression must be a string, got: ${typeof expression}`);
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}: "${expression}"`
    );
  }

  const fieldNames: FieldName[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

  const result = {} as CronFields;

  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const { min, max } = FIELD_RANGES[name];
    try {
      result[name] = parseSegment(fields[i], min, max);
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      throw new (err instanceof TypeError ? TypeError : err instanceof RangeError ? RangeError : SyntaxError)(
        `Invalid cron field "${name}" (field ${i + 1}): ${message}`
      );
    }
  }

  return result;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(from: number, to: number): number[] {
  const result: number[] = [];
  for (let i = from; i <= to; i++) result.push(i);
  return result;
}

function clamp(values: number[], min: number, max: number): number[] {
  return values.filter((v) => v >= min && v <= max);
}

function parseField(expr: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  if (expr.includes(",")) {
    return clamp(
      [...new Set(expr.split(",").flatMap((part) => parseField(part, field)))].sort((a, b) => a - b),
      min,
      max
    );
  }

  if (expr === "*") return range(min, max);

  if (expr.startsWith("*/")) {
    const step = parseInt(expr.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step in field ${field}: ${expr}`);
    return range(min, max).filter((v) => (v - min) % step === 0);
  }

  if (expr.includes("/")) {
    const [rangePart, stepPart] = expr.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step in field ${field}: ${expr}`);
    const base = rangePart === "*" ? range(min, max) : parseField(rangePart, field);
    const start = base[0];
    return clamp(
      base.filter((v) => (v - start) % step === 0),
      min,
      max
    );
  }

  if (expr.includes("-")) {
    const [fromStr, toStr] = expr.split("-");
    const from = parseInt(fromStr, 10);
    const to = parseInt(toStr, 10);
    if (isNaN(from) || isNaN(to) || from > to) throw new Error(`Invalid range in field ${field}: ${expr}`);
    return clamp(range(from, to), min, max);
  }

  const val = parseInt(expr, 10);
  if (isNaN(val)) throw new Error(`Invalid value in field ${field}: ${expr}`);
  if (val < min || val > max) throw new Error(`Value ${val} out of range [${min},${max}] for field ${field}`);
  return [val];
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) throw new Error(`Expected 5 fields, got ${fields.length}`);

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dowExpr, "dayOfWeek"),
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | unknown[];
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0 && prefix) {
    result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const safeKey = prefix ? `${prefix}.${key}` : key;
    const val = obj[key];

    if (
      val !== null &&
      typeof val === "object" &&
      !Array.isArray(val) &&
      !(val instanceof Date) &&
      !(val instanceof RegExp)
    ) {
      flattenObject(val as NestedObject, safeKey, result);
    } else {
      result[safeKey] = val as Primitive | unknown[];
    }
  }

  return result;
}

export default flattenObject;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function generateRange(start: number, end: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseField(expr: string, min: number, max: number): number[] {
  const values = new Set<number>();

  for (const part of expr.split(",")) {
    const trimmed = part.trim();

    if (trimmed === "*") {
      generateRange(min, max).forEach((v) => values.add(v));
      continue;
    }

    const stepMatch = trimmed.match(/^(\*|(\d+)-(\d+))\/(\d+)$/);
    if (stepMatch) {
      const step = parseInt(stepMatch[4], 10);
      if (step <= 0) throw new Error(`Invalid step value: ${step}`);

      let rangeStart = min;
      let rangeEnd = max;

      if (stepMatch[1] !== "*") {
        rangeStart = parseInt(stepMatch[2], 10);
        rangeEnd = parseInt(stepMatch[3], 10);
      }

      if (rangeStart < min || rangeEnd > max || rangeStart > rangeEnd) {
        throw new Error(
          `Range ${rangeStart}-${rangeEnd} out of bounds [${min}, ${max}]`
        );
      }

      generateRange(rangeStart, rangeEnd, step).forEach((v) => values.add(v));
      continue;
    }

    const rangeMatch = trimmed.match(/^(\d+)-(\d+)$/);
    if (rangeMatch) {
      const start = parseInt(rangeMatch[1], 10);
      const end = parseInt(rangeMatch[2], 10);

      if (start < min || end > max || start > end) {
        throw new Error(
          `Range ${start}-${end} out of bounds [${min}, ${max}]`
        );
      }

      generateRange(start, end).forEach((v) => values.add(v));
      continue;
    }

    const numMatch = trimmed.match(/^(\d+)$/);
    if (numMatch) {
      const num = parseInt(numMatch[1], 10);
      if (num < min || num > max) {
        throw new Error(`Value ${num} out of bounds [${min}, ${max}]`);
      }
      values.add(num);
      continue;
    }

    throw new Error(`Invalid cron field expression: "${trimmed}"`);
  }

  return [...values].sort((a, b) => a - b);
}

function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${parts.length}`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as Array<keyof CronFields>;

  return fieldNames.reduce((acc, field, index) => {
    const [min, max] = FIELD_RANGES[field];
    acc[field] = parseField(parts[index], min, max);
    return acc;
  }, {} as CronFields);
}

export default parseCron;

export class RateLimiter {
  private maxTokens: number;
  private refillRate: number;
  private refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: {
