type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function clamp(values: number[], min: number, max: number): number[] {
  return values.filter((v) => v >= min && v <= max);
}

function parseField(expr: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  // comma list — recurse each part, flatten, dedupe, sort
  if (expr.includes(",")) {
    const all = expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), field));
    return [...new Set(all)].sort((a, b) => a - b);
  }

  // wildcard
  if (expr === "*") return range(min, max);

  // step: */N or start-end/N
  if (expr.includes("/")) {
    const [base, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step in "${expr}"`);

    const [rangeStart, rangeEnd] =
      base === "*" ? [min, max] : base.split("-").map(Number);

    if (isNaN(rangeStart) || isNaN(rangeEnd))
      throw new Error(`Invalid range in "${expr}"`);

    const result: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) result.push(i);
    return clamp(result, min, max);
  }

  // range: start-end
  if (expr.includes("-")) {
    const [start, end] = expr.split("-").map(Number);
    if (isNaN(start) || isNaN(end))
      throw new Error(`Invalid range "${expr}"`);
    if (start > end) throw new Error(`Range start > end in "${expr}"`);
    return clamp(range(start, end), min, max);
  }

  // single number
  const num = parseInt(expr, 10);
  if (isNaN(num)) throw new Error(`Invalid value "${expr}" for ${field}`);
  if (num < min || num > max)
    throw new Error(`Value ${num} out of range [${min},${max}] for ${field}`);
  return [num];
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5)
    throw new Error(`Expected 5 fields, got ${fields.length}`);

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dowExpr, "dayOfWeek"),
  };
}

