  resolve: () => void;
  reject: (err: Error) => void;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: WaitEntry[];
  private scheduledTimeout: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a positive finite number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate < 0) {
      throw new RangeError("refillRate must be a non-negative finite number");
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a positive finite number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.scheduledTimeout = null;
  }

  private applyRefill(): void {
    if (this.refillRate === 0) return;

    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed < this.refillIntervalMs) return;

    const intervalsElapsed = Math.floor(elapsed / this.refillIntervalMs);
    const tokensToAdd = intervalsElapsed * this.refillRate;

    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    // Advance lastRefillTime to the boundary of the last completed interval,
    // preserving fractional elapsed time so we don't lose partial-interval progress.
    this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a non-negative finite number");
    }
    if (tokens === 0) return true;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainQueue();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(new RangeError("tokens must be a non-negative finite number"));
    }
    if (tokens === 0) return Promise.resolve();
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}`
        )
      );
    }
    if (this.refillRate === 0 && tokens > this.currentTokens) {
      return Promise.reject(
        new Error(
          "Requested tokens unavailable and refill rate is 0; wait would never resolve"
        )
      );
    }

    // Only attempt immediate consumption if no one is ahead of us in line,
    // preserving FIFO ordering and preventing starvation of waiting callers.
    this.applyRefill();
    if (this.waitQueue.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      this.scheduleNextCheck();
    });
  }

  private scheduleNextCheck(): void {
    // Only one scheduled wakeup at a time; it reschedules itself after draining.
    if (this.scheduledTimeout !== null || this.waitQueue.length === 0) return;

    this.applyRefill();

    const next = this.waitQueue[0];
    const deficit = next.tokens - this.currentTokens;

    if (deficit <= 0) {
      // Tokens are already available; drain on the next tick to avoid
      // re-entrancy issues with callers still inside waitForTokens().
      this.scheduledTimeout = setTimeout(() => {
        this.scheduledTimeout = null;
        this.drainQueue();
      }, 0);
      return;
    }

    // How many full refill intervals do we need to cover the deficit?
    const intervalsNeeded = Math.ceil(deficit / this.refillRate);

    // lastRefillTime is the boundary of the most recent completed interval,
    // so the n-th future boundary is at lastRefillTime + n * refillIntervalMs.
    const wakeAt = this.lastRefillTime + intervalsNeeded * this.refillIntervalMs;
    const delayMs = Math.max(0, wakeAt - Date.now());

    this.scheduledTimeout = setTimeout(() => {
      this.scheduledTimeout = null;
      this.drainQueue();
    }, delayMs);
  }

  private drainQueue(): void {
    this.applyRefill();

    while (this.waitQueue.length > 0) {
      const next = this.waitQueue[0];

      if (this.currentTokens >= next.tokens) {
        this.waitQueue.shift();
        this.currentTokens -= next.tokens;
        next.resolve();
      } else {
        // Not enough tokens yet; keep entry at the head and reschedule.
        break;
      }
    }

    if (this.waitQueue.length > 0) {
      this.scheduleNextCheck();
    }
  }
}

export default RateLimiter;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<FieldName, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: FieldName[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function assertInBounds(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} out of bounds [${min}, ${max}] in "${context}"`
    );
  }
}

function expandStep(
  rangeMin: number,
  rangeMax: number,
  step: number,
  context: string
): number[] {
  if (!Number.isInteger(step) || step <= 0) {
    throw new RangeError(`Invalid step value in "${context}": step must be a positive integer`);
  }
  const values: number[] = [];
  for (let v = rangeMin; v <= rangeMax; v += step) {
    values.push(v);
  }
  return values;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step: */n or start/n or start-end/n
  if (segment.includes("/")) {
    const slashIndex = segment.indexOf("/");
    const rangePart = segment.slice(0, slashIndex);
    const stepRaw = segment.slice(slashIndex + 1);
    const step = parseInt(stepRaw, 10);

    if (isNaN(step)) {
      throw new TypeError(`Non-numeric step "${stepRaw}" in "${segment}"`);
    }

    if (rangePart === "*") {
      return expandStep(min, max, step, segment);
    }

    if (rangePart.includes("-")) {
      const dashIndex = rangePart.indexOf("-");
      const startRaw = parseInt(rangePart.slice(0, dashIndex), 10);
      const endRaw   = parseInt(rangePart.slice(dashIndex + 1), 10);
      if (isNaN(startRaw) || isNaN(endRaw)) {
        throw new TypeError(`Non-numeric bounds in "${segment}"`);
      }
      assertInBounds(startRaw, min, max, segment);
      assertInBounds(endRaw, min, max, segment);
      if (startRaw > endRaw) {
        throw new RangeError(`Range start exceeds end in "${segment}"`);
      }
      return expandStep(startRaw, endRaw, step, segment);
    }

    // start/step: treat start as range floor
    const startRaw = parseInt(rangePart, 10);
    if (isNaN(startRaw)) {
      throw new TypeError(`Non-numeric start "${rangePart}" in "${segment}"`);
    }
    assertInBounds(startRaw, min, max, segment);
    return expandStep(startRaw, max, step, segment);
  }

  // Wildcard
  if (segment === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const dashIndex = segment.indexOf("-");
    const startRaw = parseInt(segment.slice(0, dashIndex), 10);
    const endRaw   = parseInt(segment.slice(dashIndex + 1), 10);
    if (isNaN(startRaw) || isNaN(endRaw)) {
      throw new TypeError(`Non-numeric bounds in "${segment}"`);
    }
    assertInBounds(startRaw, min, max, segment);
    assertInBounds(endRaw, min, max, segment);
    if (startRaw > endRaw) {
      throw new RangeError(`Range start exceeds end in "${segment}"`);
    }
    return Array.from({ length: endRaw - startRaw + 1 }, (_, i) => startRaw + i);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new TypeError(`Unrecognised cron token "${segment}"`);
  }
  assertInBounds(value, min, max, segment);
  return [value];
}

function parseField(expr: string, min: number, max: number): number[] {
  if (!expr || expr.trim() === "") {
    throw new TypeError(`Empty field expression`);
  }

  // Comma-separated list — each segment is parsed independently then merged
  if (expr.includes(",")) {
    const seen = new Set<number>();
    for (const part of expr.split(",")) {
      const trimmed = part.trim();
      if (trimmed === "") {
        throw new TypeError(`Empty segment in list expression "${expr}"`);
      }
      for (const v of parseSegment(trimmed, min, max)) {
        seen.add(v);
      }
    }
    return [...seen].sort((a, b) => a - b);
  }

  const values = parseSegment(expr, min, max);
  // Guarantee sorted, deduplicated output even for a single segment
  return [...new Set(values)].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new TypeError("parseCron: expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new RangeError(
      `parseCron: expected 5 fields but received ${parts.length} in "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const name   = FIELD_ORDER[i];
    const config = FIELD_CONFIGS[name];
    try {
      result[name] = parseField(parts[i], config.min, config.max);
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      throw new Error(`parseCron: invalid "${name}" field ("${parts[i]}"): ${message}`);
    }
  }

  return result;
}

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private tokens: number;
  private lastRefill: number;

  constructor({ maxTokens, refillRate, refillIntervalMs }: RateLimiterOptions) {
    if (maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.tokens = maxTokens;
    this.lastRefill = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefill;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.tokens = Math.min(this.maxTokens, this.tokens + intervals * this.refillRate);
      this.lastRefill += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefill = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) throw new RangeError("tokens exceeds maxTokens — can never be satisfied");

    while (!this.tryConsume(tokens)) {
      this.refill();
      const deficit = tokens - this.tokens;
      const intervalsNeeded = Math.ceil(deficit / this.refillRate);
      const waitMs = Math.max(1, intervalsNeeded * this.refillIntervalMs);
      await new Promise<void>((resolve) => setTimeout(resolve, waitMs));
    }
  }
}

export default RateLimiter;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
  reject: (err: Error) => void;
}

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Waiter[];
  private drainScheduled: boolean;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0)
      throw new RangeError(`maxTokens must be a positive finite number, got ${maxTokens}`);
    if (!Number.isFinite(refillRate) || refillRate <= 0)
      throw new RangeError(`refillRate must be a positive finite number, got ${refillRate}`);
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0)
      throw new RangeError(`refillIntervalMs must be a positive finite number, got ${refillIntervalMs}`);

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.drainScheduled = false;
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed <= 0) return;

    const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    this.lastRefillTime = now;
  }

  private msUntilAvailable(tokensNeeded: number): number {
    const deficit = tokensNeeded - this.currentTokens;
    if (deficit <= 0) return 0;
    return Math.ceil((deficit / this.refillRate) * this.refillIntervalMs);
  }

  private scheduleNextDrain(delayMs: number): void {
    if (this.drainScheduled) return;
    this.drainScheduled = true;

    setTimeout(() => {
      this.drainScheduled = false;
      this.drainQueue();
    }, Math.max(0, delayMs));
  }

  private drainQueue(): void {
    while (this.waitQueue.length > 0) {
      this.applyRefill();

      const waiter = this.waitQueue[0];

      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.waitQueue.shift();
        waiter.resolve();
      } else {
        const delay = this.msUntilAvailable(waiter.tokens);
        this.scheduleNextDrain(delay);
        break;
      }
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0)
      throw new RangeError(`tokens must be a non-negative finite number, got ${tokens}`);
    if (tokens > this.maxTokens) return false;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();

    if (this.waitQueue.length > 0) {
      this.drainQueue();
    }
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0)
      return Promise.reject(
        new RangeError(`tokens must be a non-negative finite number, got ${tokens}`)
      );

    if (tokens > this.maxTokens)
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}; can never be satisfied`
        )
      );

    if (tokens === 0) return Promise.resolve();

    return new Promise<void>((resolve, reject) => {
      const waiter: Waiter = { tokens, resolve, reject };

      this.waitQueue.push(waiter);

      if (this.waitQueue.length === 1) {
        this.drainQueue();
      }
    });
  }
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private tokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.tokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.tokens = Math.min(this.maxTokens, this.tokens + intervals * this.refillRate);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens to consume must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens to consume must be > 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens requested exceed maxTokens"));

    return new Promise((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.tokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const elapsed = Date.now() - this.lastRefillTime;
        const waitMs = Math.max(0, intervalsNeeded * this.refillIntervalMs - elapsed);

        setTimeout(attempt, waitMs || this.refillIntervalMs);
      };

      attempt();
    });
  }
}

export default RateLimiter;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      result[prefix] = null;
    } else {
      obj.forEach((item, index) => {
        const key = prefix ? `${prefix}.${index}` : `${index}`;
        flattenObject(item as NestedObject, key, result);
      });
    }
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const k of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, k)) continue;

    // Reject keys that would create ambiguous paths
    if (k.includes(".")) {
      const safeKey = k.replace(/\./g, "\uFF0E"); // fullwidth dot
      const newKey = prefix ? `${prefix}.${safeKey}` : safeKey;
      flattenObject((obj as NestedObject)[k] as NestedObject, newKey, result);
      continue;
    }

    const newKey = prefix ? `${prefix}.${k}` : k;
    const val = (obj as NestedObject)[k];

    if (val !== null && typeof val === "object") {
      flattenObject(val as NestedObject, newKey, result);
    } else {
      result[newKey] = val as Primitive;
    }
  }

  return result;
}

export default flattenObject;

export interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type CronField = keyof ParsedCron;

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  }, // 0 and 7 both represent Sunday
};

const INTEGER_RE = /^\d+$/;

function validateInteger(str: string, context: string): number {
  if (!INTEGER_RE.test(str)) {
    throw new Error(`Invalid integer "${str}" in ${context}`);
  }
  return parseInt(str, 10);
}

function parseNumber(str: string, min: number, max: number, field: CronField): number {
  const n = validateInteger(str, field);
  if (n < min || n > max) {
    throw new Error(
      `Value ${n} out of valid range [${min}, ${max}] for field "${field}"`
    );
  }
  return n;
}

function parseRange(expr: string, min: number, max: number, field: CronField): [number, number] {
  const dashIdx = expr.indexOf("-");
  if (dashIdx < 1) {
    throw new Error(`Invalid range expression "${expr}" in field "${field}"`);
  }
  const lo = parseNumber(expr.slice(0, dashIdx), min, max, field);
  const hi = parseNumber(expr.slice(dashIdx + 1), min, max, field);
  if (lo > hi) {
    throw new Error(
      `Range start ${lo} exceeds end ${hi} in field "${field}"`
    );
  }
  return [lo, hi];
}

function parseSegment(
  segment: string,
  field: CronField,
  min: number,
  max: number,
  out: Set<number>
): void {
  const slashIdx = segment.indexOf("/");

  if (slashIdx !== -1) {
    const stepStr  = segment.slice(slashIdx + 1);
    const baseExpr = segment.slice(0, slashIdx);

    if (!INTEGER_RE.test(stepStr)) {
      throw new Error(`Invalid step "${stepStr}" in field "${field}"`);
    }
    const step = parseInt(stepStr, 10);
    if (step <= 0) {
      throw new Error(`Step must be a positive integer in field "${field}", got ${step}`);
    }

    let lo: number;
    let hi: number;

    if (baseExpr === "*") {
      lo = min;
      hi = max;
    } else if (baseExpr.includes("-")) {
      [lo, hi] = parseRange(baseExpr, min, max, field);
    } else {
      lo = parseNumber(baseExpr, min, max, field);
      hi = max;
    }

    for (let i = lo; i <= hi; i += step) {
      out.add(i);
    }
    return;
  }

  if (segment === "*") {
    for (let i = min; i <= max; i++) {
      out.add(i);
    }
    return;
  }

  if (segment.includes("-")) {
    const [lo, hi] = parseRange(segment, min, max, field);
    for (let i = lo; i <= hi; i++) {
      out.add(i);
    }
    return;
  }

  out.add(parseNumber(segment, min, max, field));
}

function parseField(expr: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  if (!expr || expr.trim() === "") {
    throw new Error(`Empty expression for field "${field}"`);
  }

  const parts = expr.split(",");
  const seen = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    if (trimmed === "") {
      throw new Error(`Empty token in comma-separated list for field "${field}"`);
    }
    parseSegment(trimmed, field, min, max, seen);
  }

  // Normalize dayOfWeek: 7 (Sunday alias) → 0
  if (field === "dayOfWeek" && seen.has(7)) {
    seen.delete(7);
    seen.add(0);
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 whitespace-separated fields, got ${fields.length}`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields as [
    string, string, string, string, string
  ];

  return {
    minute:     parseField(minuteExpr, "minute"),
    hour:       parseField(hourExpr,   "hour"),
    dayOfMonth: parseField(domExpr,    "dayOfMonth"),
    month:      parseField(monthExpr,  "month"),
    dayOfWeek:  parseField(dowExpr,    "dayOfWeek"),
  };
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function expandRange(min: number, max: number): number[] {
  const result: number[] = [];
  for (let i = min; i <= max; i++) result.push(i);
  return result;
}

function parseField(field: string, min: number, max: number): number[] {
  const allValues = () => expandRange(min, max);

  // Comma-separated list
  if (field.includes(",")) {
    const values = field
      .split(",")
      .flatMap((part) => parseField(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (field === "*") return allValues();

  // Step value: */n or range/n
  if (field.includes("/")) {
    const [rangePart, stepPart] = field.split("/");
    const step = parseInt(stepPart, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: "${stepPart}"`);
    }

    let rangeMin = min;
    let rangeMax = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        [rangeMin, rangeMax] = parseRangePart(rangePart, min, max);
      } else {
        rangeMin = parseInt(rangePart, 10);
        if (isNaN(rangeMin)) {
          throw new Error(`Invalid range start: "${rangePart}"`);
        }
        validateBounds(rangeMin, min, max, rangePart);
        rangeMax = max;
      }
    }

    const result: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) result.push(i);
    return result;
  }

  // Range: n-m
  if (field.includes("-")) {
    const [rangeMin, rangeMax] = parseRangePart(field, min, max);
    return expandRange(rangeMin, rangeMax);
  }

  // Single number
  const value = parseInt(field, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid cron field value: "${field}"`);
  }
  validateBounds(value, min, max, field);
  return [value];
}

function parseRangePart(
  range: string,
  min: number,
  max: number
): [number, number] {
  const parts = range.split("-");
  if (parts.length !== 2) {
    throw new Error(`Invalid range expression: "${range}"`);
  }
  const [start, end] = parts.map((p) => parseInt(p.trim(), 10));
  if (isNaN(start) || isNaN(end)) {
    throw new Error(`Invalid range values in: "${range}"`);
  }
  validateBounds(start, min, max, range);
  validateBounds(end, min, max, range);
  if (start > end) {
    throw new Error(
      `Range start (${start}) must be <= range end (${end}) in: "${range}"`
    );
  }
  return [start, end];
}

function validateBounds(
  value: number,
  min: number,
  max: number,
  context: string
): void {
  if (value < min || value > max) {
    throw new Error(
      `Value ${value} out of bounds [${min}-${max}] in: "${context}"`
    );
  }
}

function parseCron(expression: string): CronFields {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  const result = {} as CronFields;

  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    try {
      result[name] = parseField(fields[i], min, max);
    } catch (err) {
      throw new Error(
        `Invalid "${name}" field ("${fields[i]}"): ${(err as Error).message}`
      );
    }
  }

  return result;
}

export default parseCron;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {};
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 6 },
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function range(start: number, end: number): number[] {
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function parseField(expression: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Comma-separated list
  if (expression.includes(",")) {
    const parts = expression.split(",");
    const values = parts.flatMap((part) => parseField(part.trim(), field));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (expression === "*") {
    return range(min, max);
  }

  // Step value: */step or start-end/step
  if (expression.includes("/")) {
    const [rangePart, stepStr] = expression.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step < 1) {
      throw new Error(`Invalid step value in expression: ${expression}`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      start = clamp(parseInt(startStr, 10), min, max);
      end = clamp(parseInt(endStr, 10), min, max);
    } else {
      start = clamp(parseInt(rangePart, 10), min, max);
      end = max;
    }

    if (start > end) {
      throw new RangeError(`Invalid range: ${start} > ${end}`);
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range: start-end
  if (expression.includes("-")) {
    const [startStr, endStr] = expression.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end = clamp(parseInt(endStr, 10), min, max);

    if (start > end) {
      throw new RangeError(`Invalid range: ${start} > ${end}`);
    }

    return range(start, end);
  }

  // Single number
  const value = parseInt(expression, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid cron field value: ${expression}`);
  }

  return [clamp(value, min, max)];
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${fields.length}`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] =
    fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(dayOfMonthExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dayOfWeekExpr, "dayOfWeek"),
  };
}

type Primitive = string | number | boolean | null | undefined | symbol | bigint;
type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  options: { maxDepth?: number } = {}
): Record<string, Primitive> {
  const { maxDepth = 64 } = options;

  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        input === null ? "null" : typeof input
      }`
    );
  }

  const result: Record<string, Primitive> = {};
  const seen = new WeakSet<object>();

  function recurse(node: unknown, prefix: string, depth: number): void {
    if (depth > maxDepth) {
      throw new RangeError(
        `flattenObject exceeded maximum depth of ${maxDepth}. Possible circular structure or deeply nested input.`
      );
    }

    if (isPlainObject(node)) {
      if (seen.has(node)) {
        throw new TypeError(
          `flattenObject detected a circular reference at key: "${prefix}"`
        );
      }

      const keys = Object.keys(node);

      if (keys.length === 0) {
        // Empty object: emit nothing — a key with no value is unrepresentable in flat form
        return;
      }

      seen.add(node);

      for (const key of keys) {
        if (key === "") {
          throw new TypeError(
            `flattenObject encountered an empty string key at path: "${prefix}"`
          );
        }
        const nextPrefix = prefix === "" ? key : `${prefix}.${key}`;
        recurse(node[key], nextPrefix, depth + 1);
      }

      seen.delete(node);
    } else if (Array.isArray(node)) {
      // Treat arrays as indexed objects
      if (seen.has(node)) {
        throw new TypeError(
          `flattenObject detected a circular reference at key: "${prefix}"`
        );
      }

      if (node.length === 0) {
        return;
      }

      seen.add(node);

      for (let i = 0; i < node.length; i++) {
        const nextPrefix = prefix === "" ? String(i) : `${prefix}.${i}`;
        recurse(node[i], nextPrefix, depth + 1);
      }

      seen.delete(node);
    } else {
      // Leaf value — coerce non-primitive objects (Date, RegExp, etc.) to string
      const value = node;
      if (
        value !== null &&
        typeof value === "object"
      ) {
        result[prefix] = String(value);
      } else {
        result[prefix] = value as Primitive;
      }
    }
  }

  recurse(input, "", 0);
  return result;
}

export default flattenObject;

type FlatObject = Record<string, unknown>;

function isTraversable(value: unknown): value is Record<string, unknown> | unknown[] {
  if (value === null || typeof value !== "object") return false;
  if (
    value instanceof Date ||
    value instanceof RegExp ||
    value instanceof Map ||
    value instanceof Set ||
    value instanceof Promise ||
    ArrayBuffer.isView(value)
  ) {
    return false;
  }
  return true;
}

function _flatten(
  value: unknown,
  prefix: string,
  result: FlatObject,
  seen: WeakSet<object>
): void {
  if (!isTraversable(value)) {
    result[prefix] = value;
    return;
  }

  const obj = value as Record<string, unknown>;

  if (seen.has(obj)) {
    result[prefix] = "[Circular]";
    return;
  }

  const entries = Object.entries(obj);

  if (entries.length === 0) {
    result[prefix] = value;
    return;
  }

  seen.add(obj);

  for (const [key, val] of entries) {
    const nestedKey = prefix === "" ? key : `${prefix}.${key}`;
    _flatten(val, nestedKey, result, seen);
  }

  seen.delete(obj);
}

export default function flattenObject(input: unknown): FlatObject {
  if (input === null || typeof input !== "object") {
    return {};
  }

  const result: FlatObject = {};
  const seen = new WeakSet<object>();
  const entries = Object.entries(input as Record<string, unknown>);

  if (entries.length === 0) return result;

  seen.add(input as object);

  for (const [key, val] of entries) {
    _flatten(val, key, result, seen);
  }

  seen.delete(input as object);

  return result;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  return Array.from({ length: end - start + 1 }, (_, i) => i + start);
}

function clamp(values: number[], min: number, max: number): number[] {
  return values.filter((v) => v >= min && v <= max);
}

function parseField(expr: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  if (expr.includes(",")) {
    return [
      ...new Set(expr.split(",").flatMap((part) => parseField(part.trim(), field))),
    ].sort((a, b) => a - b);
  }

  if (expr.includes("/")) {
    const [rangeExpr, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step in field "${field}": ${expr}`);

    let start: number;
    let end: number;

    if (rangeExpr === "*") {
      start = min;
      end = max;
    } else if (rangeExpr.includes("-")) {
      const [s, e] = rangeExpr.split("-").map(Number);
      start = s;
      end = e;
    } else {
      start = parseInt(rangeExpr, 10);
      end = max;
    }

    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid step range in field "${field}": ${expr}`);

    const result: number[] = [];
    for (let v = start; v <= end; v += step) result.push(v);
    return clamp(result, min, max);
  }

  if (expr === "*") return range(min, max);

  if (expr.includes("-")) {
    const [s, e] = expr.split("-").map(Number);
    if (isNaN(s) || isNaN(e)) throw new Error(`Invalid range in field "${field}": ${expr}`);
    if (s > e) throw new Error(`Range start > end in field "${field}": ${expr}`);
    return clamp(range(s, e), min, max);
  }

  const val = parseInt(expr, 10);
  if (isNaN(val)) throw new Error(`Invalid value in field "${field}": ${expr}`);
  if (val < min || val > max) throw new Error(`Value ${val} out of range [${min},${max}] for field "${field}"`);
  return [val];
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) throw new Error(`Expected 5 fields, got ${fields.length}`);

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dowExpr, "dayOfWeek"),
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (prefix) result[prefix] = obj;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {};
    return result;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const sanitizedKey = key.includes(".") ? `[${key}]` : key;
    const newKey = prefix ? `${prefix}.${sanitizedKey}` : sanitizedKey;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | unknown[];
    }
  }

  return result;
}

export default flattenObject;

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private tokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.tokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.tokens = Math.min(this.maxTokens, this.tokens + intervals * this.refillRate);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens exceeds maxTokens — will never be satisfiable"));

    return new Promise<void>((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.tokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const delay = Math.max(1, intervalsNeeded * this.refillIntervalMs);

        setTimeout(attempt, delay);
      };

      attempt();
    });
  }
}

export default RateLimiter;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;

  private currentTokens: number;
  private lastRefillTime: number;

  private waitQueue: Array<{
    tokens: number;
    resolve: () => void;
  }> = [];

  private processingQueue = false;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private lazyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed <= 0) return;

    const intervalsElapsed = elapsed / this.refillIntervalMs;
    const tokensToAdd = intervalsElapsed * this.refillRate;

    if (tokensToAdd >= 1) {
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime = now;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.lazyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.lazyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(`Requested ${tokens} tokens exceeds maxTokens (${this.maxTokens})`)
      );
    }

    return new Promise<void>((resolve) => {
      this.waitQueue.push({ tokens, resolve });
      this.drainQueue();
    });
  }

  private drainQueue(): void {
    if (this.processingQueue || this.waitQueue.length === 0) return;

    this.processingQueue = true;

    const attempt = () => {
      this.lazyRefill();

      const next = this.waitQueue[0];
      if (!next) {
        this.processingQueue = false;
        return;
      }

      if (this.currentTokens >= next.tokens) {
        this.currentTokens -= next.tokens;
        this.waitQueue.shift();
        next.resolve();
        // Process next waiter synchronously — avoids unnecessary timer overhead
        attempt();
      } else {
        // Compute exact wait time until enough tokens accumulate
        const deficit = next.tokens - this.currentTokens;
        const intervalsNeeded = deficit / this.refillRate;
        const msNeeded = Math.ceil(intervalsNeeded * this.refillIntervalMs);
        setTimeout(attempt, Math.max(1, msNeeded));
      }
    };

    attempt();
  }
}

export default RateLimiter;

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldBounds = { min: number; max: number };

const FIELD_BOUNDS: Record<keyof CronResult, FieldBounds> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

function assertInRange(val: number, bounds: FieldBounds, context: string): void {
  if (!Number.isInteger(val) || val < bounds.min || val > bounds.max) {
    throw new RangeError(
      `${context}: value ${val} out of range [${bounds.min}-${bounds.max}]`
    );
  }
}

function parseSegment(segment: string, bounds: FieldBounds): number[] {
  const { min, max } = bounds;

  // Step: */n or start-end/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (!Number.isInteger(step) || isNaN(step) || step < 1) {
      throw new SyntaxError(`Invalid step value: "${stepStr}"`);
    }

    let rangeMin = min;
    let rangeMax = max;

    if (rangePart !== "*") {
      if (!rangePart.includes("-")) {
        throw new SyntaxError(`Invalid step range: "${rangePart}"`);
      }
      const [startStr, endStr] = rangePart.split("-");
      rangeMin = parseInt(startStr, 10);
      rangeMax = parseInt(endStr, 10);
      assertInRange(rangeMin, bounds, "step range start");
      assertInRange(rangeMax, bounds, "step range end");
      if (rangeMin > rangeMax) {
        throw new RangeError(`Step range start ${rangeMin} > end ${rangeMax}`);
      }
    }

    const result: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      result.push(i);
    }
    return result;
  }

  // Wildcard
  if (segment === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => i + min);
  }

  // Range: n-m
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    assertInRange(start, bounds, "range start");
    assertInRange(end, bounds, "range end");
    if (start > end) {
      throw new RangeError(`Range start ${start} > end ${end}`);
    }
    return Array.from({ length: end - start + 1 }, (_, i) => i + start);
  }

  // Single number
  const val = parseInt(segment, 10);
  if (isNaN(val)) {
    throw new SyntaxError(`Invalid cron segment: "${segment}"`);
  }
  assertInRange(val, bounds, "value");
  return [val];
}

function parseField(field: string, bounds: FieldBounds): number[] {
  // Comma-separated list — each part parsed independently
  const parts = field.split(",");
  if (parts.length > 1) {
    const seen = new Set<number>();
    const result: number[] = [];
    for (const part of parts) {
      for (const v of parseSegment(part.trim(), bounds)) {
        if (!seen.has(v)) {
          seen.add(v);
          result.push(v);
        }
      }
    }
    return result.sort((a, b) => a - b);
  }

  return parseSegment(field.trim(), bounds);
}

export function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;

  const result: CronResult = {
    minute:     parseField(minuteField, FIELD_BOUNDS.minute),
    hour:       parseField(hourField,   FIELD_BOUNDS.hour),
    dayOfMonth: parseField(domField,    FIELD_BOUNDS.dayOfMonth),
    month:      parseField(monthField,  FIELD_BOUNDS.month),
    dayOfWeek:  parseField(dowField,    FIELD_BOUNDS.dayOfWeek),
  };

  // Normalise dayOfWeek: Sunday can be 0 or 7 — map 7 → 0, deduplicate
  result.dayOfWeek = [...new Set(result.dayOfWeek.map(d => d === 7 ? 0 : d))].sort(
    (a, b) => a - b
  );

  return result;
}

export default parseCron;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  return Array.from({ length: end - start + 1 }, (_, i) => i + start);
}

function clamp(values: number[], min: number, max: number): number[] {
  return values.filter((v) => v >= min && v <= max);
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step: */n or x-y/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${stepStr}`);

    let base: number[];
    if (rangePart === "*") {
      base = range(min, max);
    } else if (rangePart.includes("-")) {
      const [lo, hi] = rangePart.split("-").map(Number);
      if (isNaN(lo) || isNaN(hi)) throw new Error(`Invalid range: ${rangePart}`);
      base = clamp(range(lo, hi), min, max);
    } else {
      const start = parseInt(rangePart, 10);
      if (isNaN(start)) throw new Error(`Invalid value: ${rangePart}`);
      base = range(start, max);
    }
    return base.filter((v) => (v - base[0]) % step === 0);
  }

  // Wildcard
  if (segment === "*") return range(min, max);

  // Range: x-y
  if (segment.includes("-")) {
    const [lo, hi] = segment.split("-").map(Number);
    if (isNaN(lo) || isNaN(hi)) throw new Error(`Invalid range: ${segment}`);
    const result = clamp(range(lo, hi), min, max);
    if (result.length === 0) throw new Error(`Range ${segment} out of bounds [${min}-${max}]`);
    return result;
  }

  // Number
  const val = parseInt(segment, 10);
  if (isNaN(val)) throw new Error(`Invalid value: ${segment}`);
  if (val < min || val > max) throw new Error(`Value ${val} out of range [${min}-${max}]`);
  return [val];
}

function parseField(field: string, min: number, max: number): number[] {
  const parts = field.split(",");
  const values = new Set<number>();
  for (const part of parts) {
    for (const v of parseSegment(part.trim(), min, max)) {
      values.add(v);
    }
  }
  return [...values].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) throw new Error(`Expected 5 fields, got ${fields.length}`);

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = fields;
  const fieldNames: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];
  const fieldStrs = [minuteStr, hourStr, domStr, monthStr, dowStr];

  const result = {} as CronResult;
  for (let i = 0; i < 5; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    result[name] = parseField(fieldStrs[i], min, max);
  }
  return result;
}

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private tokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.tokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.tokens = Math.min(this.maxTokens, this.tokens + intervals * this.refillRate);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens exceeds maxTokens — will never be satisfiable"));

    return new Promise((resolve) => {
      const attempt = () => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.tokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const msUntilRefill = this.refillIntervalMs - (Date.now() - this.lastRefillTime);
        const delay = Math.max(0, msUntilRefill + (intervalsNeeded - 1) * this.refillIntervalMs);

        setTimeout(attempt, delay);
      };

      attempt();
    });
  }
}

export default RateLimiter;

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens requested exceeds maxTokens"));

    return new Promise<void>((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const waitMs = Math.max(1, intervalsNeeded * this.refillIntervalMs);

        setTimeout(attempt, waitMs);
      };

      attempt();
    });
  }
}

export default RateLimiter;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0,  6],
};

function assertRange(value: number, min: number, max: number, field: string): void {
  if (value < min || value > max || !Number.isInteger(value)) {
    throw new RangeError(`Field "${field}": value ${value} outside valid range [${min}, ${max}]`);
  }
}

function parseSegment(segment: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];
  const all = (): number[] => Array.from({ length: max - min + 1 }, (_, i) => i + min);

  // Step: */n or x/n — not supporting range/step combo (e.g. 1-10/2) for simplicity... actually let's support it
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new SyntaxError(`Field "${field}": invalid step "${stepStr}"`);
    }
    let base: number[];
    if (rangePart === "*") {
      base = all();
    } else if (rangePart.includes("-")) {
      const [lo, hi] = rangePart.split("-").map(Number);
      if (isNaN(lo) || isNaN(hi)) throw new SyntaxError(`Field "${field}": invalid range in step "${rangePart}"`);
      assertRange(lo, min, max, field);
      assertRange(hi, min, max, field);
      if (lo > hi) throw new RangeError(`Field "${field}": range start ${lo} > end ${hi}`);
      base = Array.from({ length: hi - lo + 1 }, (_, i) => i + lo);
    } else {
      const start = parseInt(rangePart, 10);
      if (isNaN(start)) throw new SyntaxError(`Field "${field}": invalid step base "${rangePart}"`);
      assertRange(start, min, max, field);
      base = Array.from({ length: max - start + 1 }, (_, i) => i + start);
    }
    return base.filter((_, i) => i % step === 0);
  }

  // Wildcard
  if (segment === "*") return all();

  // Range
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) throw new SyntaxError(`Field "${field}": invalid range "${segment}"`);
    const lo = parseInt(parts[0], 10);
    const hi = parseInt(parts[1], 10);
    if (isNaN(lo) || isNaN(hi)) throw new SyntaxError(`Field "${field}": non-numeric range "${segment}"`);
    assertRange(lo, min, max, field);
    assertRange(hi, min, max, field);
    if (lo > hi) throw new RangeError(`Field "${field}": range start ${lo} > end ${hi}`);
    return Array.from({ length: hi - lo + 1 }, (_, i) => i + lo);
  }

  // Number
  const n = parseInt(segment, 10);
  if (isNaN(n) || segment.trim() === "") throw new SyntaxError(`Field "${field}": invalid value "${segment}"`);
  assertRange(n, min, max, field);
  return [n];
}

function parseField(expr: string, field: CronField): number[] {
  const segments = expr.split(",");
  if (segments.length === 0 || segments.some(s => s === "")) {
    throw new SyntaxError(`Field "${field}": empty or trailing comma in "${expr}"`);
  }
  const values = new Set<number>();
  for (const seg of segments) {
    for (const v of parseSegment(seg.trim(), field)) {
      values.add(v);
    }
  }
  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") throw new TypeError("Expression must be string");
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(`Expected 5 fields, got ${fields.length}`);
  }
  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;
  return {
    minute:     parseField(minuteExpr, "minute"),
    hour:       parseField(hourExpr,   "hour"),
    dayOfMonth: parseField(domExpr,    "dayOfMonth"),
    month:      parseField(monthExpr,  "month"),
    dayOfWeek:  parseField(dowExpr,    "dayOfWeek"),
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject | Record<string, unknown>,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  for (const key of Object.keys(obj)) {
    const value = obj[key];
    const flatKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as Record<string, unknown>, flatKey, result);
    } else {
      result[flatKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (prefix) result[prefix] = JSON.stringify(obj);
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = "{}";
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const val = obj[key];

    if (val !== null && typeof val === "object" && !Array.isArray(val)) {
      flattenObject(val as NestedObject, newKey, result);
    } else if (Array.isArray(val)) {
      result[newKey] = JSON.stringify(val);
    } else {
      result[newKey] = val as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | unknown[] };
type FlatObject = Record<string, Primitive>;

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (prefix) result[prefix] = JSON.stringify(obj);
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const safeKey = String(key);
    if (safeKey.length === 0) continue; // skip empty string keys — unpredictable dot path

    const fullKey = prefix ? `${prefix}.${safeKey}` : safeKey;
    const val = obj[key];

    if (
      val !== null &&
      typeof val === "object" &&
      !Array.isArray(val) &&
      !(val instanceof Date) &&
      !(val instanceof RegExp)
    ) {
      flattenObject(val as NestedObject, fullKey, result);
    } else if (val instanceof Date) {
      result[fullKey] = val.toISOString();
    } else if (val instanceof RegExp) {
      result[fullKey] = val.toString();
    } else if (Array.isArray(val)) {
      result[fullKey] = JSON.stringify(val);
    } else {
      result[fullKey] = val as Primitive;
    }
  }

  return result;
}

export default flattenObject;
